  1→//! Prompt configuration and loading for review specialists.
  2→//!
  3→//! Loads specialist review prompts from `.forge/autoresearch/prompts/<specialist>.md`
  4→//! files, falling back to hardcoded defaults derived from [`SpecialistType`] data
  5→//! when no file exists or the file is malformed.
  6→
  7→use std::path::{Path, PathBuf};
  8→
  9→use serde::{Deserialize, Serialize};
 10→use tracing::warn;
 11→
 12→use super::SpecialistType;
 13→
 14→/// Mode indicating whether a specialist operates as gating or advisory.
 15→///
 16→/// This is **informational only** — it never controls actual gating behavior.
 17→/// Gating decisions are made by [`ReviewSpecialist::is_gating()`](super::ReviewSpecialist::is_gating).
 18→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
 19→#[serde(rename_all = "lowercase")]
 20→pub enum PromptMode {
 21→    /// Specialist findings can block phase progression.
 22→    Gating,
 23→    /// Specialist findings are reported but do not block.
 24→    Advisory,
 25→}
 26→
 27→/// Configuration for a specialist's review prompt.
 28→///
 29→/// Contains the specialist identity, mode, focus areas, and the full prompt body.
 30→/// Loaded from markdown files or constructed from hardcoded defaults.
 31→#[derive(Debug, Clone, Serialize, Deserialize)]
 32→pub struct PromptConfig {
 33→    /// The specialist's display name.
 34→    pub specialist_name: String,
 35→    /// Whether this specialist is gating or advisory (informational only).
 36→    pub mode: PromptMode,
 37→    /// Specific areas this specialist should focus on during review.
 38→    pub focus_areas: Vec<String>,
 39→    /// The full prompt body text.
 40→    pub body: String,
 41→}
 42→
 43→/// Internal struct for deserializing YAML frontmatter from prompt files.
 44→#[derive(Deserialize)]
 45→struct PromptFrontmatter {
 46→    #[allow(dead_code)]
 47→    specialist: Option<String>,
 48→    mode: Option<String>,
 49→}
 50→
 51→/// Loader for specialist review prompts.
 52→///
 53→/// Resolves prompts from `{forge_dir}/autoresearch/prompts/{agent_name}.md` files,
 54→/// falling back to hardcoded defaults on any error.
 55→pub struct PromptLoader {
 56→    forge_dir: PathBuf,
 57→}
 58→
 59→impl PromptLoader {
 60→    /// Create a new loader rooted at the given forge directory.
 61→    pub fn new(forge_dir: impl Into<PathBuf>) -> Self {
 62→        Self {
 63→            forge_dir: forge_dir.into(),
 64→        }
 65→    }
 66→
 67→    /// Resolve the file path for a specialist's prompt file.
 68→    pub fn prompt_path(&self, specialist: &SpecialistType) -> PathBuf {
 69→        self.forge_dir
 70→            .join("autoresearch")
 71→            .join("prompts")
 72→            .join(format!("{}.md", specialist.agent_name()))
 73→    }
 74→
 75→    /// Load the prompt configuration for a specialist.
 76→    ///
 77→    /// Attempts to read from `{forge_dir}/autoresearch/prompts/{agent_name}.md`.
 78→    /// Falls back to hardcoded defaults derived from [`SpecialistType`] on any error
 79→    /// (missing file, malformed YAML, empty file, missing sections).
 80→    pub fn load(&self, specialist: &SpecialistType) -> PromptConfig {
 81→        let path = self.prompt_path(specialist);
 82→        match self.try_load_from_file(&path, specialist) {
 83→            Ok(config) => config,
 84→            Err(reason) => {
 85→                warn!(
 86→                    specialist = specialist.agent_name(),
 87→                    path = %path.display(),
 88→                    reason = %reason,
 89→                    "Falling back to hardcoded defaults for specialist prompt"
 90→                );
 91→                self.build_default(specialist)
 92→            }
 93→        }
 94→    }
 95→
 96→    /// Attempt to load a prompt config from a file.
 97→    fn try_load_from_file(
 98→        &self,
 99→        path: &Path,
100→        specialist: &SpecialistType,
101→    ) -> Result<PromptConfig, String> {
102→        let content = std::fs::read_to_string(path).map_err(|e| format!("read error: {e}"))?;
103→
104→        if content.trim().is_empty() {
105→            return Err("empty file".to_string());
106→        }
107→
108→        let (frontmatter, body) = parse_frontmatter(&content)?;
109→        let mode = match frontmatter.mode.as_deref() {
110→            Some("gating") => PromptMode::Gating,
111→            Some("advisory") => PromptMode::Advisory,
112→            _ => default_mode(specialist),
113→        };
114→
115→        let focus_areas = extract_focus_areas(&body);
116→        let focus_areas = if focus_areas.is_empty() {
117→            specialist
118→                .focus_areas()
119→                .into_iter()
120→                .map(String::from)
121→                .collect()
122→        } else {
123→            focus_areas
124→        };
125→
126→        Ok(PromptConfig {
127→            specialist_name: specialist.display_name().to_string(),
128→            mode,
129→            focus_areas,
130→            body,
131→        })
132→    }
133→
134→    /// Build a hardcoded default prompt config for a specialist.
135→    fn build_default(&self, specialist: &SpecialistType) -> PromptConfig {
136→        let display_name = specialist.display_name();
137→        let focus_areas: Vec<String> = specialist
138→            .focus_areas()
139→            .into_iter()
140→            .map(String::from)
141→            .collect();
142→
143→        let focus_list = focus_areas
144→            .iter()
145→            .map(|a| format!("- {a}"))
146→            .collect::<Vec<_>>()
147→            .join("\n");
148→
149→        let body = format!(
150→            "# {display_name} Review\n\
151→             \n\
152→             You are a code review specialist focused on **{display_name}** concerns.\n\
153→             \n\
154→             ## Focus Areas\n\
155→             {focus_list}\n\
156→             \n\
157→             ## Review Instructions\n\
158→             1. Examine the code changes carefully\n\
159→             2. Check for issues in your focus areas\n\
160→             3. For each issue found: identify file/line, describe, suggest fix, classify severity\n\
161→             \n\
162→             ## Output Format\n\
163→             JSON with verdict, summary, findings array"
164→        );
165→
166→        PromptConfig {
167→            specialist_name: display_name.to_string(),
168→            mode: default_mode(specialist),
169→            focus_areas,
170→            body,
171→        }
172→    }
173→}
174→
175→/// Parse YAML frontmatter delimited by `---` lines.
176→fn parse_frontmatter(content: &str) -> Result<(PromptFrontmatter, String), String> {
177→    let trimmed = content.trim_start();
178→    if !trimmed.starts_with("---") {
179→        return Err("no frontmatter delimiter found".to_string());
180→    }
181→
182→    // Find the closing ---
183→    let after_first = &trimmed[3..];
184→    let after_first = after_first.trim_start_matches(['\r', '\n']);
185→    let end_idx = after_first
186→        .find("\n---")
187→        .ok_or_else(|| "no closing frontmatter delimiter".to_string())?;
188→
189→    let yaml_str = &after_first[..end_idx];
190→    let body_start = end_idx + 4; // skip \n---
191→    let body = after_first[body_start..].trim_start_matches(['\r', '\n']).to_string();
192→
193→    let frontmatter: PromptFrontmatter =
194→        serde_yaml::from_str(yaml_str).map_err(|e| format!("YAML parse error: {e}"))?;
195→
196→    Ok((frontmatter, body))
197→}
198→
199→/// Extract focus areas from a `## Focus Areas` section in markdown.
200→///
201→/// Parses bullet points (`- `) until the next `## ` heading or EOF.
202→fn extract_focus_areas(body: &str) -> Vec<String> {
203→    let mut in_section = false;
204→    let mut areas = Vec::new();
205→
206→    for line in body.lines() {
207→        if line.starts_with("## Focus Areas") {
208→            in_section = true;
209→            continue;
210→        }
211→        if in_section {
212→            if line.starts_with("## ") {
213→                break;
214→            }
215→            let trimmed = line.trim();
216→            if let Some(item) = trimmed.strip_prefix("- ") {
217→                areas.push(item.to_string());
218→            }
219→        }
220→    }
221→
222→    areas
223→}
224→
225→/// Get the default mode for a specialist based on its gating default.
226→fn default_mode(specialist: &SpecialistType) -> PromptMode {
227→    if specialist.default_gating() {
228→        PromptMode::Gating
229→    } else {
230→        PromptMode::Advisory
231→    }
232→}
